28|// Complex arithmetic helpers
29|inline complex_t complex_add(complex_t a, complex_t b) {
30|    return complex_t(a.re + b.re, a.im + b.im);
31|}
32|
33|inline complex_t complex_sub(complex_t a, complex_t b) {
34|    return complex_t(a.re - b.re, a.im - b.im);
35|}
