37|inline complex_t complex_mul(complex_t a, complex_t b) {
38|    fixed_t re = a.re * b.re - a.im * b.im;
39|    fixed_t im = a.re * b.im + a.im * b.re;
40|    return complex_t(re, im);
41|}
42|
43|inline complex_t complex_conj(complex_t a) {
44|    return complex_t(a.re, -a.im);
